using SeedApi;

var client = new SeedApiClient();
await client.CreatePlantOrderAsync(
    new CreatePlantOrderRequest
    {
        PlantId = "plantId",
        Body = new PlantOrder
        {
            OrderId = "orderId",
            Amount = 1.1,
            Currency = "currency",
            PlantName = "plantName",
        },
    }
);
